`navigator.serial.requestPort()` requires a user gesture; we wire it to a click handler.

```ts
import { ConduytDevice } from 'conduyt-js'
import { WebSerialTransport } from 'conduyt-js/transports/web-serial'

document.querySelector<HTMLButtonElement>('#connect')!.addEventListener('click', async () => {
  const port = await navigator.serial.requestPort()
  const device = await ConduytDevice.connect(new WebSerialTransport({ port, baudRate: 115200 }))
  await device.pin(5).mode('output')
  await device.pin(5).write(1)
})
```

`BLETransport` filters on the CONDUYT GATT service UUID. The user picks the device from the browser's pairing dialog (which requires a user gesture).

```ts
import { ConduytDevice } from 'conduyt-js'
import { BLETransport } from 'conduyt-js/transports/ble'

document.querySelector<HTMLButtonElement>('#connect')!.addEventListener('click', async () => {
  const device = await ConduytDevice.connect(new BLETransport())
  await device.ping()
  console.log('connected, capabilities =', device.capabilities)
})
```

MQTT transport doesn't need a user gesture; it connects to the broker and routes by `conduyt/<deviceId>/...` topics.

```ts
import { ConduytDevice } from 'conduyt-js'
import { MQTTTransport } from 'conduyt-js/transports/mqtt'

const device = await ConduytDevice.connect(
  new MQTTTransport({
    broker: 'mqtt://broker.local',
    deviceId: 'kitchen-01',
  })
)

const v = await device.pin(14).analogRead()
console.log('A0 =', v)

await device.disconnect()
```

`MockTransport.sentPackets` records every outgoing packet so the test can assert against the wire bytes without real hardware.

```ts
import { describe, it, expect } from 'vitest'
import { ConduytDevice } from 'conduyt-js'
import { MockTransport } from 'conduyt-js/transports/mock'

describe('pin write', () => {
  it('sends one packet per write', async () => {
    const transport = new MockTransport()
    const device = await ConduytDevice.connect(transport)

    transport.clearSent()
    await device.pin(13).mode('output')
    await device.pin(13).write(1)

    expect(transport.sentPackets.length).toBe(2)
    expect(transport.lastSent).toBeDefined()
  })
})
```

`ReconnectTransport.onReconnect` is a setter for a callback the wrapper fires after a successful reconnect.

```ts
import { ConduytDevice, ReconnectTransport } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const transport = new ReconnectTransport(
  new SerialTransport({ path: '/dev/ttyACM0' }),
  { initialDelay: 1000, maxDelay: 30000, multiplier: 2 }
)
transport.onReconnect = () => {
  console.log('reconnected')
}

const device = await ConduytDevice.connect(transport)
await device.ping()
```

HSV-to-RGB done host-side; we push the whole strip every frame.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytNeoPixel } from 'conduyt-js/modules/neopixel'

function hsv(h: number): [number, number, number] {
  const i = Math.floor(h * 6), f = h * 6 - i
  const q = 1 - f, t = f
  switch (i % 6) {
    case 0: return [255, Math.round(t * 255), 0]
    case 1: return [Math.round(q * 255), 255, 0]
    case 2: return [0, 255, Math.round(t * 255)]
    case 3: return [0, Math.round(q * 255), 255]
    case 4: return [Math.round(t * 255), 0, 255]
    default: return [255, 0, Math.round(q * 255)]
  }
}

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)
const pixels = new ConduytNeoPixel(device)
await pixels.begin(5, 60)
await pixels.setBrightness(40)

const CYCLE_MS = 6000
for (;;) {
  const base = (Date.now() % CYCLE_MS) / CYCLE_MS
  for (let i = 0; i < 60; i++) {
    const [r, g, b] = hsv((base + i / 60) % 1)
    await pixels.setPixel(i, r, g, b)
  }
  await pixels.show()
  await new Promise((r) => setTimeout(r, 33))
}
```

`begin(pin, type)`: type 22 for DHT22, type 11 for DHT11. `read()` returns `{ temperature, humidity }`.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytDHT } from 'conduyt-js/modules/dht'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const dht = new ConduytDHT(device)
await dht.begin(4, 22)
const { temperature, humidity } = await dht.read()
console.log(`T=${temperature.toFixed(2)}C  RH=${humidity.toFixed(1)}%`)
```

`onTick(handler)` registers an event listener; the handler receives the absolute count and the delta from the last tick.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytEncoder } from 'conduyt-js/modules/encoder'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const enc = new ConduytEncoder(device)
await enc.attach(4, 5)
enc.onTick((count, delta) => {
  console.log(`count=${count}  delta=${delta}`)
})
```

`onDone(handler)` fires after a `move` or `moveTo` completes; we wrap it in a Promise to await sequentially.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytStepper } from 'conduyt-js/modules/stepper'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)
const step = new ConduytStepper(device)
await step.config(3, 4, 5)

function waitDone(): Promise<number> {
  return new Promise((resolve) => {
    step.onDone((position) => resolve(position))
  })
}

await step.moveTo(1000, 800)
await waitDone()
await step.moveTo(0, 800)
await waitDone()
```

Pass the numeric `SUB_MODE.FALLING` (0x03). The host doesn't poll; the firmware emits PIN_EVENT on each detected edge.

```ts
import { ConduytDevice, SUB_MODE } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

await device.pin(2).mode('input_pullup')
for await (const _ of device.pin(2).subscribe({ mode: SUB_MODE.FALLING })) {
  console.log('pressed')
}
```

`device.datastream(name).subscribe()` returns an AsyncIterable of decoded values matching the firmware-declared type.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

for await (const value of device.datastream('temperature').subscribe()) {
  console.log(`T=${(value as number).toFixed(2)} C`)
}
```

`device.i2c().readReg(addr, reg, count)` issues a register-read on the firmware-side bus.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const i2c = device.i2c()
const bytes = await i2c.readReg(0x76, 0xD0, 1)
console.log(`chip id = 0x${bytes[0].toString(16).padStart(2, '0')}`)

await device.disconnect()
```

`i2c.write(addr, data)` and `i2c.read(addr, count)` are separate calls. Some sensors expect a tiny delay between the configuration write and the data read.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const i2c = device.i2c()
await i2c.write(0x44, new Uint8Array([0x01, 0x42]))
await new Promise((r) => setTimeout(r, 10))
const data = await i2c.read(0x44, 6)
console.log(Array.from(data).map((b) => b.toString(16).padStart(2, '0')).join(' '))
```

`device.capabilities` is the parsed HelloResp; it lists pins, modules, datastreams, and bus counts.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const caps = device.capabilities
if (!caps) throw new Error('not connected')
console.log(`device: ${caps.firmwareName} v${caps.firmwareVersion.join('.')}`)
for (const ds of caps.datastreams) {
  console.log(`  [${ds.index}] ${ds.name} type=0x${ds.type.toString(16)} writable=${ds.writable} unit=${ds.unit || '(none)'}`)
}
```

`ConduytNAKError.errorName` resolves the numeric error code into a human-readable name (e.g. INVALID_PIN).

```ts
import { ConduytDevice, ConduytNAKError } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

try {
  await device.pin(200).mode('output')
} catch (e) {
  if (e instanceof ConduytNAKError) {
    console.error(`NAK: ${e.errorName} (code=0x${e.code.toString(16)})`)
  } else {
    throw e
  }
}
```

The timeout is set in `ConduytDevice.connect(transport, { timeoutMs })`. Retry logic lives in the application layer.

```ts
import { ConduytDevice, ConduytTimeoutError } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' }),
  { timeoutMs: 250 }
)

async function tryRead(pin: number, attempts = 3): Promise<number> {
  for (let i = 0; i < attempts; i++) {
    try {
      return await device.pin(pin).analogRead()
    } catch (e) {
      if (!(e instanceof ConduytTimeoutError)) throw e
      console.warn(`timeout, attempt ${i + 1}`)
    }
  }
  throw new Error(`pin ${pin} read failed after ${attempts} attempts`)
}

console.log('value =', await tryRead(14))
```

After `disconnect`, the SDK rejects new commands without touching the wire.

```ts
import { ConduytDevice, ConduytDisconnectedError } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)
await device.disconnect()

try {
  await device.pin(13).write(1)
} catch (e) {
  if (e instanceof ConduytDisconnectedError) {
    console.error('expected: disconnected')
  } else {
    throw e
  }
}
```

`device.module(name)` throws `ConduytCapabilityError` synchronously if the module isn't in the capability list.

```ts
import { ConduytDevice, ConduytCapabilityError } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

try {
  device.module('not-a-real-module')
} catch (e) {
  if (e instanceof ConduytCapabilityError) {
    console.warn('module missing:', e.message)
  } else {
    throw e
  }
}
```

`ConduytOTA.flash` chunks the image, computes SHA256 via Web Crypto, and reports progress through `onProgress`.

```ts
import { ConduytDevice, ConduytOTA } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

if (!device.capabilities?.otaCapable) {
  throw new Error('device firmware was not built with -DCONDUYT_OTA')
}

declare const firmware: Uint8Array
const ota = new ConduytOTA(device)
await ota.flash(firmware, {
  onProgress: (sent, total) => {
    const pct = ((sent / total) * 100).toFixed(1)
    process.stdout.write(`\rOTA ${pct}%`)
  },
})
console.log('\ndone, device will reboot')
```
